private void xrTableCell8_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e) {
    XRTableCell cell = sender as XRTableCell;

// Get values from the data source
decimal rearingFemaleOpen = Convert.ToDecimal(GetCurrentColumnValue("RearingFemaleOpen") ?? 0);
decimal fdoa = Convert.ToDecimal(GetCurrentColumnValue("FDOA") ?? 0);

if (rearingFemaleOpen > 0)
{
    // Calculate: (FDOA * 100) / RearingFemaleOpen
    decimal result = (fdoa * 100.0m) / rearingFemaleOpen;
    cell.Text = result.ToString("N2"); // Formats to 2 decimal places
}
else
{
    cell.Text = "0.00";
}
}

