private void xrTableCell99_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e) {
    XRTableCell cell = sender as XRTableCell;

// Helper function to safely convert values
decimal SafeConvert(object value)
{
    if (value == null || value == DBNull.Value || string.IsNullOrEmpty(value.ToString()))
        return 0;
    return Convert.ToDecimal(value);
}

// Get values directly from the current row
decimal rearingFemaleDepl = SafeConvert(GetCurrentColumnValue("RearingFemaleDepl"));
decimal rearFemaleCK = SafeConvert(GetCurrentColumnValue("RearFemaleCK"));
decimal rearFemaleCS = SafeConvert(GetCurrentColumnValue("RearFemaleCS"));
decimal rearingFemaleError = SafeConvert(GetCurrentColumnValue("RearingFemaleError"));

// Calculate {@RearingTotalErrorF} for this row
decimal rearingTotalErrorF = rearingFemaleDepl + rearFemaleCK + rearFemaleCS + rearingFemaleError;

// Get RearingFemaleOpen from current row
decimal rearingFemaleOpen = SafeConvert(GetCurrentColumnValue("RearingFemaleOpen"));

if (rearingFemaleOpen > 0)
{
    // Calculate: ({@RearingTotalErrorF} * 100) / RearingFemaleOpen
    decimal result = (rearingTotalErrorF * 100.0m) / rearingFemaleOpen;
    string formattedResult = result.ToString("N2");

    cell.Text = formattedResult ;

}
else
{
    cell.Text = "0.00";
}
}

